  1→import type { Block, ImportJob } from "@chat-exporter/shared";
  2→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  3→
  4→import { ErrorBoundary } from "@/components/error-boundary";
  5→import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
  6→import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
  7→import { ArtifactView } from "@/components/format-workspace/artifact-view";
  8→import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
  9→import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
 10→import {
 11→  formatMarkdownLinesLabel,
 12→  formatMessageBlockLabel,
 13→  getImportStageLabel,
 14→  miscLabels,
 15→} from "@/components/format-workspace/labels";
 16→import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
 17→import { MarkdownView } from "@/components/format-workspace/markdown-view";
 18→import { ReaderView } from "@/components/format-workspace/reader-view";
 19→import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
 20→import { buildReaderHtml } from "@/components/format-workspace/reader-html-export";
 21→import {
 22→  applyMarkdownRules,
 23→  buildReaderEffectsMap,
 24→} from "@/components/format-workspace/rule-engine";
 25→import { SaveIndicator } from "@/components/format-workspace/save-indicator";
 26→import { StatusHeader } from "@/components/format-workspace/status-header";
 27→import {
 28→  type AdjustmentSelection,
 29→  adjustableViews,
 30→  type EditMode,
 31→  type ViewMode,
 32→} from "@/components/format-workspace/types";
 33→import { UndoToast } from "@/components/format-workspace/undo-toast";
 34→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 35→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 36→import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
 37→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 38→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 39→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 40→import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
 41→import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
 42→import { useSnapshots } from "@/components/format-workspace/use-snapshots";
 43→import { VersionsModal } from "@/components/format-workspace/versions-modal";
 44→
 45→type ActiveStage = {
 46→  detail: string;
 47→  label: string;
 48→} | null;
 49→
 50→type FormatWorkspaceProps = {
 51→  activeStage: ActiveStage;
 52→  elapsedTime: string;
 53→  job: ImportJob;
 54→  view: ViewMode;
 55→  onViewChange: (view: ViewMode) => void;
 56→};
 57→
 58→function _describeSelectionLabel(selection: AdjustmentSelection) {
 59→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 60→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 61→  }
 62→
 63→  return formatMessageBlockLabel(
 64→    selection.messageRole,
 65→    selection.messageIndex + 1,
 66→    selection.blockType,
 67→  );
 68→}
 69→
 70→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 71→  if (!job.artifacts) {
 72→    return "Artefakt ist noch nicht verfügbar.";
 73→  }
 74→
 75→  switch (view) {
 76→    case "markdown":
 77→      return job.artifacts.markdown;
 78→    case "handover":
 79→      return job.artifacts.handover;
 80→    case "json":
 81→      return job.artifacts.json;
 82→  }
 83→}
 84→
 85→export function FormatWorkspace({
 86→  activeStage,
 87→  elapsedTime,
 88→  job,
 89→  view,
 90→  onViewChange,
 91→}: FormatWorkspaceProps) {
 92→  const isAdjustableView = adjustableViews.has(view);
 93→
 94→  const session = useAdjustmentSession(view, job.id);
 95→  const rules = useFormatRules(view, job.id);
 96→  const snapshots = useSnapshots(job.id);
 97→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 98→  const resolvedMessages = useResolvedConversation(
 99→    job.conversation,
100→    messageEdits.editedMessagesMap,
101→  );
102→  const autoSnapshot = useAutoSnapshot({
103→    activeSnapshot: snapshots.activeSnapshot,
104→    create: snapshots.create,
105→    activate: snapshots.activate,
106→  });
107→  const deletion = useMessageDeletion(job.id);
108→  const deletionToast = useDeletionToast();
109→  const [editMode, setEditMode] = useState<EditMode>("view");
110→
111→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
112→  const handleEditModeChange = useCallback(
113→    (mode: EditMode) => {
114→      if (mode === "edit" && session.adjustModeEnabled) {
115→        session.toggleAdjustMode();
116→      }
117→      setEditMode(mode);
118→    },
119→    [session],
120→  );
121→
122→  const handleToggleAdjustMode = useCallback(() => {
123→    if (!session.adjustModeEnabled && editMode === "edit") {
124→      setEditMode("view");
125→    }
126→    session.toggleAdjustMode();
127→  }, [session, editMode]);
128→
129→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
130→
131→  // beforeunload warning when unsaved edits exist
132→  useEffect(() => {
133→    if (!messageEdits.isSaving) return;
134→    const handler = (e: BeforeUnloadEvent) => {
135→      e.preventDefault();
136→    };
137→    window.addEventListener("beforeunload", handler);
138→    return () => window.removeEventListener("beforeunload", handler);
139→  }, [messageEdits.isSaving]);
140→
141→  const handleBlocksChange = useCallback(
142→    (messageId: string, blocks: Block[]) => {
143→      void autoSnapshot.ensureSnapshot().then((ready) => {
144→        if (ready) {
145→          messageEdits.saveEdit(messageId, blocks);
146→        }
147→      });
148→    },
149→    [autoSnapshot, messageEdits],
150→  );
151→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
152→  const [deleteDialog, setDeleteDialog] = useState<{
153→    messageId: string;
154→    isRound: boolean;
155→    preview: string;
156→  } | null>(null);
157→  const popover = useAdjustmentPopover();
158→
159→  const handleDeleteMessage = useCallback(
160→    (messageId: string) => {
161→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
162→      const preview =
163→        msg?.blocks
164→          .map((b) => ("text" in b ? b.text : b.type))
165→          .join(" ")
166→          .slice(0, 200) ?? messageId;
167→      setDeleteDialog({ messageId, isRound: false, preview });
168→    },
169→    [job.conversation?.messages],
170→  );
171→
172→  const handleDeleteRound = useCallback(
173→    (messageId: string) => {
174→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
175→      const preview =
176→        msg?.blocks
177→          .map((b) => ("text" in b ? b.text : b.type))
178→          .join(" ")
179→          .slice(0, 200) ?? messageId;
180→      setDeleteDialog({ messageId, isRound: true, preview });
181→    },
182→    [job.conversation?.messages],
183→  );
184→
185→  const handleConfirmDelete = useCallback(
186→    async (reason?: string) => {
187→      if (!deleteDialog) return;
188→      const { messageId, isRound } = deleteDialog;
189→      setDeleteDialog(null);
190→      if (isRound) {
191→        const result = await deletion.deleteRound(messageId, reason);
192→        deletionToast.showDeletedToast(messageId, true, result.length);
193→      } else {
194→        await deletion.deleteMessage(messageId, reason);
195→        deletionToast.showDeletedToast(messageId, false);
196→      }
197→    },
198→    [deleteDialog, deletion, deletionToast],
199→  );
200→
201→  const handleUndoDelete = useCallback(async () => {
202→    if (!deletionToast.toast) return;
203→    await deletion.restoreMessage(deletionToast.toast.messageId);
204→    deletionToast.dismissToast();
205→  }, [deletion, deletionToast]);
206→
207→  const mergedRef = useCallback(
208→    (node: HTMLElement | null) => {
209→      (
210→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
211→      ).current = node;
212→      (
213→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
214→      ).current = node;
215→    },
216→    [session.sectionRef, popover.containerRef],
217→  );
218→
219→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
220→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
221→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
222→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
223→  const displayedMarkdown = useMemo(() => {
224→    if (view !== "markdown") return artifact;
225→    try {
226→      return applyMarkdownRules(artifact, rules.activeRules);
227→    } catch {
228→      return artifact;
229→    }
230→  }, [artifact, rules.activeRules, view]);
231→
232→  const resolvedConversation = useMemo(() => {
233→    if (!job.conversation) return undefined;
234→    return {
235→      ...job.conversation,
236→      messages: resolvedMessages.map((rm) => ({
237→        id: rm.id,
238→        role: rm.role,
239→        blocks: rm.blocks,
240→      })),
241→    };
242→  }, [job.conversation, resolvedMessages]);
243→
244→  const readerEffectsMap = useMemo(
245→    () =>
246→      view === "reader" && resolvedConversation
247→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
248→        : new Map(),
249→    [rules.activeRules, resolvedConversation, view],
250→  );
251→
252→  const handleCopyMessage = useCallback(
253→    (messageId: string) => {
254→      const msg = resolvedConversation?.messages.find(
255→        (m) => m.id === messageId,
256→      );
257→      if (!msg) return;
258→      void copyMessageToClipboard(msg, view, msg.blocks);
259→    },
260→    [resolvedConversation, view],
261→  );
262→
263→  const handleDownload = useMemo(() => {
264→    if (view === "markdown") {
265→      return () => {
266→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
267→        const url = URL.createObjectURL(blob);
268→        const a = document.createElement("a");
269→        a.href = url;
270→        a.download = `export-${job.id}.md`;
271→        document.body.appendChild(a);
272→        a.click();
273→        document.body.removeChild(a);
274→        setTimeout(() => URL.revokeObjectURL(url), 100);
275→      };
276→    }
277→    if (view === "reader" && resolvedConversation) {
278→      return () => {
279→        const html = buildReaderHtml(
280→          resolvedConversation,
281→          readerEffectsMap,
282→          resolvedConversation.title ?? `export-${job.id}`,
283→        );
284→        const blob = new Blob([html], { type: "text/html" });
285→        const url = URL.createObjectURL(blob);
286→        const a = document.createElement("a");
287→        a.href = url;
288→        a.download = `export-${job.id}.html`;
289→        document.body.appendChild(a);
290→        a.click();
291→        document.body.removeChild(a);
292→        setTimeout(() => URL.revokeObjectURL(url), 100);
293→      };
294→    }
295→    if ((view === "handover" || view === "json") && artifact) {
296→      return () => {
297→        const ext = view === "json" ? "json" : "md";
298→        const blob = new Blob([artifact], { type: "text/plain" });
299→        const url = URL.createObjectURL(blob);
300→        const a = document.createElement("a");
301→        a.href = url;
302→        a.download = `export-${job.id}.${ext}`;
303→        document.body.appendChild(a);
304→        a.click();
305→        document.body.removeChild(a);
306→        setTimeout(() => URL.revokeObjectURL(url), 100);
307→      };
308→    }
309→    return undefined;
310→  }, [view, displayedMarkdown, job.id, resolvedConversation, readerEffectsMap, artifact]);
311→  const showPopover =
312→    session.adjustModeEnabled &&
313→    Boolean(session.activeSelection) &&
314→    Boolean(session.activeAnchor);
315→
316→  const popoverCallbacksRef = useRef({
317→    handleDiscardSession: session.handleDiscardSession,
318→    activeSessionDetail: session.activeSessionDetail,
319→    handleRejectLastChange: rules.handleRejectLastChange,
320→    setReplyVisible: session.setReplyVisible,
321→  });
322→  popoverCallbacksRef.current = {
323→    handleDiscardSession: session.handleDiscardSession,
324→    activeSessionDetail: session.activeSessionDetail,
325→    handleRejectLastChange: rules.handleRejectLastChange,
326→    setReplyVisible: session.setReplyVisible,
327→  };
328→
329→  const handlePopoverClose = useCallback(() => {
330→    popoverCallbacksRef.current.handleDiscardSession();
331→  }, []);
332→
333→  const handleRejectLastChange = useCallback(() => {
334→    const {
335→      activeSessionDetail,
336→      handleRejectLastChange: reject,
337→      setReplyVisible,
338→    } = popoverCallbacksRef.current;
339→    if (activeSessionDetail) {
340→      void reject(activeSessionDetail).then((success) => {
341→        if (success) setReplyVisible(false);
342→      });
343→    }
344→  }, []);
345→
346→  const sessionError =
347→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
348→
349→  const viewErrorFallback = (_error: Error, reset: () => void) => (
350→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
351→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
352→      <button
353→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
354→        type="button"
355→        onClick={reset}
356→      >
357→        {miscLabels.retryButton}
358→      </button>
359→    </div>
360→  );
361→
362→  return (
363→    <section
364→      ref={mergedRef}
365→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
366→    >
367→      <StatusHeader
368→        activeStage={activeStage}
369→        elapsedTime={elapsedTime}
370→        job={job}
371→      />
372→
373→      {job.warnings.length > 0 ? (
374→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
375→          {job.warnings[0]}
376→        </div>
377→      ) : null}
378→
379→      {job.status === "failed" ? (
380→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
381→          <p className="font-medium">{miscLabels.importFailed}</p>
382→          {job.errorStage && job.errorStage !== "done" && (
383→            <p className="text-sm mt-1">
384→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
385→            </p>
386→          )}
387→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
388→        </div>
389→      ) : job.status === "queued" || job.status === "running" ? (
390→        <LoadingStateBlock stageDetail={activeStage?.detail} />
391→      ) : (
392→        <div className="space-y-4">
393→          <CompletedToolbar
394→            adjustModeEnabled={session.adjustModeEnabled}
395→            editMode={editMode}
396→            isAdjustableView={isAdjustableView}
397→            rules={rules}
398→            view={view}
399→            onDownloadMarkdown={handleDownload}
400→            onEditModeChange={handleEditModeChange}
401→            onToggleAdjustMode={handleToggleAdjustMode}
402→            onViewChange={onViewChange}
403→            deletionsCount={deletion.deletionsCount}
404→            showDeleted={deletion.showDeleted}
405→            snapshotCount={snapshots.snapshots.length}
406→            onVersionsClick={() => setVersionsModalOpen(true)}
407→            onToggleShowDeleted={() =>
408→              deletion.setShowDeleted(!deletion.showDeleted)
409→            }
410→          />
411→
412→          {sessionError && !session.adjustModeEnabled ? (
413→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
414→              {sessionError}
415→            </div>
416→          ) : null}
417→
418→          {view === "reader" ? (
419→            <ErrorBoundary fallback={viewErrorFallback}>
420→              <div className="space-y-2">
421→                <div className="flex justify-end">
422→                  <SaveIndicator
423→                    isSaving={messageEdits.isSaving}
424→                    hasEdits={hasEdits}
425→                  />
426→                </div>
427→                <ReaderView
428→                  activeRules={rules.activeRules}
429→                  conversation={resolvedConversation}
430→                  adjustModeEnabled={session.adjustModeEnabled}
431→                  editMode={editMode === "edit"}
432→                  effectsMap={readerEffectsMap}
433→                  highlightedRuleId={rules.hoveredRuleId}
434→                  selectedBlock={
435→                    view === "reader" ? session.activeSelection : null
436→                  }
437→                  onSelectBlock={session.handleSelectionChange}
438→                  deletedMessageIds={deletion.deletedMessageIds}
439→                  showDeleted={deletion.showDeleted}
440→                  onBlocksChange={handleBlocksChange}
441→                  onCopyMessage={handleCopyMessage}
442→                  onDeleteMessage={handleDeleteMessage}
443→                  onDeleteRound={handleDeleteRound}
444→                  onRestoreMessage={deletion.restoreMessage}
445→                />
446→              </div>
447→            </ErrorBoundary>
448→          ) : view === "markdown" ? (
449→            <ErrorBoundary fallback={viewErrorFallback}>
450→              <MarkdownView
451→                activeRules={rules.activeRules}
452→                content={displayedMarkdown}
453→                adjustModeEnabled={session.adjustModeEnabled}
454→                highlightedRuleId={rules.hoveredRuleId}
455→                selectedRange={session.activeSelection}
456→                onSelectLines={session.handleSelectionChange}
457→              />
458→            </ErrorBoundary>
459→          ) : (
460→            <ErrorBoundary fallback={viewErrorFallback}>
461→              <ArtifactView content={artifact} />
462→            </ErrorBoundary>
463→          )}
464→
465→          {session.showGuide ? (
466→            <AdjustmentModeGuide
467→              view={view}
468→              onDismiss={() => session.setGuideDismissed(true)}
469→            />
470→          ) : null}
471→
472→          <ErrorBoundary
473→            fallback={
474→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
475→                {miscLabels.adjustmentLoadError}
476→              </div>
477→            }
478→          >
479→            <AdjustmentPopover
480→              anchor={session.activeAnchor ?? null}
481→              containerRef={session.sectionRef}
482→              draftMessage={session.activeDraftMessage}
483→              error={session.activeSessionError}
484→              isLoading={session.activeSessionLoading || session.isDiscarding}
485→              isSubmitting={session.isSubmitting}
486→              open={
487→                showPopover &&
488→                Boolean(session.activeSelection) &&
489→                Boolean(session.activeAnchor)
490→              }
491→              sessionDetail={session.activeSessionDetail}
492→              showReply={session.replyVisible}
493→              view={view}
494→              onClose={handlePopoverClose}
495→              onDraftMessageChange={session.handleDraftMessageChange}
496→              onRejectLastChange={handleRejectLastChange}
497→              onSubmitMessage={session.handleSubmitMessage}
498→            />
499→          </ErrorBoundary>
500→        </div>
501→      )}
502→
503→      {deleteDialog && (
504→        <DeleteMessageDialog
505→          messagePreview={deleteDialog.preview}
506→          isRound={deleteDialog.isRound}
507→          onConfirm={(reason) => {
508→            void handleConfirmDelete(reason);
509→          }}
510→          onCancel={() => setDeleteDialog(null)}
511→        />
512→      )}
513→
514→      {deletionToast.toast && (
515→        <UndoToast
516→          message={deletionToast.toast.message}
517→          onUndo={() => {
518→            void handleUndoDelete();
519→          }}
520→          onDismiss={deletionToast.dismissToast}
521→        />
522→      )}
523→
524→      <VersionsModal
525→        open={versionsModalOpen}
526→        onOpenChange={setVersionsModalOpen}
527→        snapshots={snapshots.snapshots}
528→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
529→        onActivate={(snapshotId) => {
530→          void snapshots.activate(snapshotId);
531→        }}
532→        onDeactivate={() => {
533→          void snapshots.deactivate();
534→        }}
535→        onCreate={(label) => {
536→          void snapshots.create(label);
537→        }}
538→        onRename={(snapshotId, label) => {
539→          void snapshots.rename(snapshotId, label);
540→        }}
541→        onDelete={(snapshotId) => {
542→          void snapshots.delete(snapshotId);
543→        }}
544→      />
545→    </section>
546→  );
547→}
