  1→import {
  2→  Download,
  3→  Eye,
  4→  EyeOff,
  5→  History,
  6→  Pencil,
  7→  Settings2,
  8→} from "lucide-react";
  9→
 10→import {
 11→  adjustmentLabels,
 12→  getAdjustViewLabel,
 13→  getEndAdjustLabel,
 14→  getViewLabel,
 15→} from "@/components/format-workspace/labels";
 16→import { RulesListModal } from "@/components/format-workspace/rules-list-modal";
 17→import type { EditMode, ViewMode } from "@/components/format-workspace/types";
 18→import type { useFormatRules } from "@/components/format-workspace/use-format-rules";
 19→import { Button } from "@/components/ui/button";
 20→
 21→const outputViews: { value: ViewMode; label: string }[] = [
 22→  { value: "reader", label: getViewLabel("reader") },
 23→  { value: "markdown", label: getViewLabel("markdown") },
 24→  { value: "handover", label: getViewLabel("handover") },
 25→  { value: "json", label: getViewLabel("json") },
 26→];
 27→
 28→type CompletedToolbarProps = {
 29→  adjustModeEnabled: boolean;
 30→  deletionsCount?: number;
 31→  editMode: EditMode;
 32→  isAdjustableView: boolean;
 33→  rules: ReturnType<typeof useFormatRules>;
 34→  showDeleted?: boolean;
 35→  snapshotCount?: number;
 36→  view: ViewMode;
 37→  onDownloadMarkdown?: () => void;
 38→  onEditModeChange: (mode: EditMode) => void;
 39→  onToggleAdjustMode: () => void;
 40→  onToggleShowDeleted?: () => void;
 41→  onVersionsClick?: () => void;
 42→  onViewChange: (view: ViewMode) => void;
 43→};
 44→
 45→export function CompletedToolbar({
 46→  adjustModeEnabled,
 47→  deletionsCount,
 48→  editMode,
 49→  isAdjustableView,
 50→  rules,
 51→  showDeleted,
 52→  snapshotCount,
 53→  view,
 54→  onDownloadMarkdown,
 55→  onEditModeChange,
 56→  onToggleAdjustMode,
 57→  onToggleShowDeleted,
 58→  onVersionsClick,
 59→  onViewChange,
 60→}: CompletedToolbarProps) {
 61→  return (
 62→    <div className="space-y-2">
 63→      {/* Row 1: Format buttons */}
 64→      <div data-testid="toolbar-format-row" className="flex flex-wrap gap-2">
 65→        {outputViews.map((outputView) => (
 66→          <Button
 67→            key={outputView.value}
 68→            data-testid={`format-view-${outputView.value}`}
 69→            type="button"
 70→            size="sm"
 71→            variant={view === outputView.value ? "default" : "outline"}
 72→            onClick={() => onViewChange(outputView.value)}
 73→          >
 74→            {outputView.label}
 75→          </Button>
 76→        ))}
 77→      </div>
 78→
 79→      {/* Row 2: Action buttons */}
 80→      <div
 81→        data-testid="toolbar-action-row"
 82→        className="flex flex-wrap items-center gap-2"
 83→      >
 84→        {onDownloadMarkdown ? (
 85→          <Button
 86→            data-testid="toolbar-download"
 87→            type="button"
 88→            size="sm"
 89→            variant="outline"
 90→            onClick={onDownloadMarkdown}
 91→          >
 92→            <Download className="mr-2 h-4 w-4" />
