  3→// ---------------------------------------------------------------------------
  4→// Block → Markdown
  5→// ---------------------------------------------------------------------------
  6→
  7→function blockToMarkdown(block: Block): string {
  8→  switch (block.type) {
  9→    case "paragraph":
 10→      return block.text;
 11→    case "heading":
 12→      return `${"#".repeat(block.level)} ${block.text}`;
 13→    case "code":
 14→      return `\`\`\`${block.language}\n${block.text}\n\`\`\``;
 15→    case "list":
 16→      return block.items
 17→        .map((item, i) => (block.ordered ? `${i + 1}. ${item}` : `- ${item}`))
 18→        .join("\n");
 19→    case "quote":
 20→      return `> ${block.text}`;
 21→    case "table": {
 22→      const header = `| ${block.headers.join(" | ")} |`;
 23→      const separator = `| ${block.headers.map(() => "---").join(" | ")} |`;
 24→      const rows = block.rows.map((row) => `| ${row.join(" | ")} |`).join("\n");
 25→      return `${header}\n${separator}\n${rows}`;
 26→    }
 27→  }
 28→}
 29→
 30→// ---------------------------------------------------------------------------
 31→// Block → HTML (for reader clipboard)
 32→// ---------------------------------------------------------------------------
 33→
 34→function blockToHtml(block: Block): string {
 35→  switch (block.type) {
 36→    case "paragraph":
 37→      return `<p style="margin:0 0 0.75em">${escapeHtml(block.text)}</p>`;
 38→    case "heading": {
 39→      const tag = `h${block.level}` as const;
 40→      return `<${tag} style="margin:0 0 0.5em">${escapeHtml(block.text)}</${tag}>`;
 41→    }
 42→    case "code":
 43→      return `<pre style="margin:0 0 0.75em;padding:0.75em;background:#f5f5f5;border-radius:6px;overflow-x:auto"><code>${escapeHtml(block.text)}</code></pre>`;
 44→    case "list": {
 45→      const tag = block.ordered ? "ol" : "ul";
 46→      const items = block.items
 47→        .map((item) => `<li>${escapeHtml(item)}</li>`)
 48→        .join("");
 49→      return `<${tag} style="margin:0 0 0.75em;padding-left:1.5em">${items}</${tag}>`;
 50→    }
 51→    case "quote":
 52→      return `<blockquote style="margin:0 0 0.75em;padding-left:1em;border-left:3px solid #ddd;color:#555">${escapeHtml(block.text)}</blockquote>`;
 53→    case "table": {
 54→      const headerCells = block.headers
 55→        .map(
 56→          (h) =>
 57→            `<th style="border:1px solid #ddd;padding:4px 8px">${escapeHtml(h)}</th>`,
 58→        )
 59→        .join("");
 60→      const rows = block.rows
 61→        .map(
 62→          (row) =>
 63→            `<tr>${row.map((cell) => `<td style="border:1px solid #ddd;padding:4px 8px">${escapeHtml(cell)}</td>`).join("")}</tr>`,
 64→        )
 65→        .join("");
 66→      return `<table style="margin:0 0 0.75em;border-collapse:collapse"><thead><tr>${headerCells}</tr></thead><tbody>${rows}</tbody></table>`;
 67→    }
 68→  }
 69→}
 70→
 71→function escapeHtml(text: string): string {
 72→  return text
 73→    .replace(/&/g, "&amp;")
 74→    .replace(/</g, "&lt;")
 75→    .replace(/>/g, "&gt;")
 76→    .replace(/"/g, "&quot;");
 77→}
 78→
 79→// ---------------------------------------------------------------------------
 80→// Block → Plain text (for handover)
 81→// ---------------------------------------------------------------------------
 82→
 83→function blockToPlainText(block: Block): string {
 84→  switch (block.type) {
 85→    case "paragraph":
 86→    case "heading":
 87→    case "quote":
 88→      return block.text;
 89→    case "code":
 90→      return block.text;
 91→    case "list":
 92→      return block.items.join("\n");
 93→    case "table":
 94→      return [
 95→        block.headers.join("\t"),
 96→        ...block.rows.map((r) => r.join("\t")),
 97→      ].join("\n");
 98→  }
 99→}
