102→// Public API
103→// ---------------------------------------------------------------------------
104→
105→export async function copyMessageToClipboard(
106→  message: Message,
107→  format: "reader" | "markdown" | "json" | "handover",
108→  blocks: Block[],
109→): Promise<void> {
110→  switch (format) {
111→    case "reader": {
112→      const html = blocks.map(blockToHtml).join("\n");
113→      const blob = new Blob([html], { type: "text/html" });
114→      const item = new ClipboardItem({ "text/html": blob });
115→      await navigator.clipboard.write([item]);
116→      break;
117→    }
118→    case "markdown": {
119→      const md = blocks.map(blockToMarkdown).join("\n\n");
120→      await navigator.clipboard.writeText(md);
121→      break;
122→    }
123→    case "json": {
124→      const json = JSON.stringify(message, null, 2);
125→      await navigator.clipboard.writeText(json);
126→      break;
127→    }
128→    case "handover": {
129→      const text = blocks.map(blockToPlainText).join("\n\n");
130→      await navigator.clipboard.writeText(text);
131→      break;
132→    }
133→  }
134→}
